DROP DATABASE IF EXISTS loja;
CREATE DATABASE loja CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE loja;

-- ------------------------------------------------------------
-- Tabela: cliente
-- ------------------------------------------------------------
CREATE TABLE cliente (
    id      INT AUTO_INCREMENT PRIMARY KEY,
    nome    VARCHAR(40)  NOT NULL,
    email   VARCHAR(80)  NOT NULL UNIQUE,
    ativo   TINYINT(1)   NOT NULL DEFAULT 1,
    senha   VARCHAR(64)  NOT NULL,
    perfil  ENUM('adm','cliente') NOT NULL DEFAULT 'cliente'
);

-- ADM padrao: email = adm@loja.com / senha = admin123
 '240be518fabd2724ddb6f04eeb1da5967448d7e831c08c8fa822809f74c720a9', 'adm');

-- ------------------------------------------------------------
-- Tabela: produto
-- ------------------------------------------------------------
CREATE TABLE produto (
    id        INT AUTO_INCREMENT PRIMARY KEY,
    descricao VARCHAR(200) NOT NULL,
    preco     DOUBLE(7,2)  NOT NULL,
    foto      VARCHAR(255) NULL,
    estoque   INT          NOT NULL DEFAULT 0
);

-- ------------------------------------------------------------
-- 35.000 produtos de calcados
-- ------------------------------------------------------------







































































-- ------------------------------------------------------------
-- Tabela: pedido
-- ------------------------------------------------------------
CREATE TABLE pedido (
    id         INT AUTO_INCREMENT PRIMARY KEY,
    cliente_id INT            NOT NULL,
    dt_criacao DATETIME       NOT NULL,
    total      DECIMAL(10,2)  NOT NULL DEFAULT 0,
    FOREIGN KEY (cliente_id) REFERENCES cliente(id)
);

-- ------------------------------------------------------------
-- Tabela: pedido_item
-- ------------------------------------------------------------
CREATE TABLE pedido_item (
    id             INT AUTO_INCREMENT PRIMARY KEY,
    pedido_id      INT            NOT NULL,
    produto_id     INT            NOT NULL,
    preco_unitario DECIMAL(10,2)  NOT NULL DEFAULT 0,
    quantidade     INT            NOT NULL,
    FOREIGN KEY (pedido_id)  REFERENCES pedido(id),
    FOREIGN KEY (produto_id) REFERENCES produto(id)
);

-- ------------------------------------------------------------
-- Verificacao final
-- ------------------------------------------------------------
SELECT 'Banco criado com sucesso!' AS status;
SELECT COUNT(*) AS total_produtos FROM produto;
SELECT COUNT(*) AS total_clientes FROM cliente;